+    #[test]
+    fn execute_refuses_unresolved_conflicts() {
+        let (src, dst) = setup_temp_trees();
+        write_file(src.path(), "wa.toml", "# source");
+        write_file(dst.path(), "wa.toml", "# dest");
+
+        let plan = build_file_plan(
+            src.path(),
+            dst.path(),
+            SyncCategory::Config,
+            SyncDirection::Push,
+            &[],
+            &[],
